import { defineJob } from 'hound/';

export const sendEmailJob = defineJob<App, { to: string; subject: string }>(
  'email.send',
  async (ctx) => {
    // ctx.data is typed: { to: string; subject: string }
    await sendEmail(ctx.data);
  },
  {
    queue: 'emails',
    concurrency: 5,
    attempts: 3,
    retryBackoff: 'exponential',
  }
);

