import { defineJob } from '@hushkey/hound';

export const midWorldJob = defineJob(
  'mid-world',
  async (ctx) => {
    console.log('runs every 2 minutes');
  },
  {
    queue: 'scheduled',
    repeat: { pattern: '*/2 * * * *' },
  },
);

// multiple jobs in one file — both get registered
