import type { userReadJob } from '../_tasks/request.job.ts';
import type { midWorldJob } from '../_scheduled/mid-world.job.ts';
import type { JobDefinition } from 'jsr:@hushkey/hound';

type _Data<T> = T extends JobDefinition<any, infer D> ? D : never;

export interface HoundJobMap {
  'user.read': _Data<typeof userReadJob>;   // { name: string; email: string }
  'mid-world': _Data<typeof midWorldJob>;   // void
}

export class HoundClient {
  async emit<K extends keyof HoundJobMap>(
    event: K,
    data: HoundJobMap[K],
    options?: EmitOptions,
  ): Promise<string> { ... }

  async emitBatch(jobs: EmitBatchJob[]): Promise<string[]> { ... }

  readonly management: {
    jobs: { find, get, delete, pause, resume, retry, promote };
    queues: { find, stats, pause, resume, reset };
  };
}

import { HoundClient } from '../gen/hound-client.ts';

const hound = new HoundClient('http://localhost:3000', {
  auth: Deno.env.get('HOUND_TOKEN'),
});

// TypeScript enforces the payload shape — 'user.read' requires { name, email }
await hound.emit('user.read', { name: 'Alice', email: 'alice@example.com' });

// Type error — 'unknown-event' is not in HoundJobMap
await hound.emit('unknown-event', {});
